SELECT 
FROM shipments


        AND status = #{status}


        AND carrier = #{carrier}


ORDER BY shipped_at DESC

SELECT s.id, s.order_id, s.carrier, s.tracking_no, s.status, s.shipped_at, o.order_no, o.user_id, o.amount AS order_amount FROM shipments s JOIN orders o ON o.id = s.order_id
o.order_no = #{orderNo}
o.user_id = #{userId}
s.status != 'DELETED'
ORDER BY ${orderBy}
